import{_ as r,C as o,o as t,c as s,a2 as a,b as l,w as i,a as c,E as h,a3 as g}from"./chunks/framework.B72_uj9U.js";const w=JSON.parse('{"title":"TongAgents — Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/tongagents/architecture.md","filePath":"research/agents/tongagents/architecture.md"}'),u={name:"research/agents/tongagents/architecture.md"};function d(m,e,p,f,b,A){const n=o("Mermaid");return t(),s("div",null,[e[1]||(e[1]=a('<h1 id="tongagents-—-architecture" tabindex="-1">TongAgents — Architecture <a class="header-anchor" href="#tongagents-—-architecture" aria-label="Permalink to &quot;TongAgents — Architecture&quot;">​</a></h1><blockquote><p>⚠️ <strong>No source code is publicly available.</strong> Everything in this file is inferred from benchmark results, the agent&#39;s name, and BIGAI&#39;s broader research portfolio. Speculative claims are clearly marked.</p></blockquote><h2 id="what-we-can-infer" tabindex="-1">What We Can Infer <a class="header-anchor" href="#what-we-can-infer" aria-label="Permalink to &quot;What We Can Infer&quot;">​</a></h2><h3 id="multi-agent-system-high-confidence" tabindex="-1">Multi-Agent System (High Confidence) <a class="header-anchor" href="#multi-agent-system-high-confidence" aria-label="Permalink to &quot;Multi-Agent System (High Confidence)&quot;">​</a></h3><p>The &quot;Agents&quot; suffix (plural) strongly suggests a <strong>multi-agent architecture</strong> rather than a single-agent loop. This is consistent with:</p><ul><li>BIGAI&#39;s extensive research on multi-agent systems and coordination</li><li>The institute&#39;s work on cognitive architectures that decompose tasks into specialized modules</li><li>The naming convention: &quot;TongAgents&quot; not &quot;TongAgent&quot; or &quot;TongCoder&quot;</li></ul><p>A plausible architecture would involve specialized agents for different task phases — planning, execution, verification — coordinated by an orchestrator.</p><h3 id="model-agnostic-design-high-confidence" tabindex="-1">Model-Agnostic Design (High Confidence) <a class="header-anchor" href="#model-agnostic-design-high-confidence" aria-label="Permalink to &quot;Model-Agnostic Design (High Confidence)&quot;">​</a></h3><p>TongAgents was tested with both Gemini 3.1 Pro and Claude Opus 4.6, achieving strong results with both. This indicates:</p><ul><li>The system is not hard-coded to a specific model&#39;s API or capabilities</li><li>Prompts and tool interfaces are likely abstracted behind a model-neutral layer</li><li>The agent framework handles model-specific details (token limits, tool calling formats) separately from task logic</li></ul><h3 id="cognitive-architecture-influence-moderate-confidence" tabindex="-1">Cognitive Architecture Influence (Moderate Confidence) <a class="header-anchor" href="#cognitive-architecture-influence-moderate-confidence" aria-label="Permalink to &quot;Cognitive Architecture Influence (Moderate Confidence)&quot;">​</a></h3><p>BIGAI&#39;s core research theme is <strong>cognitive architecture</strong> — building AI systems that mirror human cognitive processes. It would be surprising if TongAgents did <em>not</em> incorporate ideas from this research:</p><ul><li><strong>Hierarchical task decomposition</strong> — breaking complex terminal tasks into subtasks</li><li><strong>Planning before execution</strong> — generating a plan before running commands</li><li><strong>Self-monitoring</strong> — evaluating progress and adjusting strategy</li><li><strong>Memory/knowledge management</strong> — maintaining structured context about the task state</li></ul><h3 id="performance-characteristics" tabindex="-1">Performance Characteristics <a class="header-anchor" href="#performance-characteristics" aria-label="Permalink to &quot;Performance Characteristics&quot;">​</a></h3><p>The benchmark results reveal architectural clues:</p><ul><li><strong>80.2% with Gemini 3.1 Pro</strong> (Rank #3) — very strong, near the top of the leaderboard</li><li><strong>~71.9% with Claude Opus 4.6</strong> (Rank #13) — still solid but notably lower</li><li>The <strong>~8pp gap</strong> suggests the architecture may rely on capabilities where Gemini excels (potentially: longer context utilization, structured output, or specific reasoning patterns)</li></ul><h2 id="speculative-architecture-diagram" tabindex="-1">Speculative Architecture Diagram <a class="header-anchor" href="#speculative-architecture-diagram" aria-label="Permalink to &quot;Speculative Architecture Diagram&quot;">​</a></h2>',17)),(t(),l(g,null,{default:i(()=>[h(n,{id:"mermaid-114",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20OA%5B%22Orchestrator%20Agent%3Cbr%2F%3E(task%20decomposition%2C%20plan%20management)%22%5D%0A%20%20%20%20OA%20--%3E%20PA%5B%22Planning%20Agent%3Cbr%2F%3E-%20Analyze%20task%3Cbr%2F%3E-%20Generate%20plan%22%5D%0A%20%20%20%20OA%20--%3E%20EA%5B%22Execution%20Agent%3Cbr%2F%3E-%20Run%20commands%3Cbr%2F%3E-%20Handle%20errors%22%5D%0A%20%20%20%20OA%20--%3E%20VA%5B%22Verification%20Agent%3Cbr%2F%3E-%20Check%20output%3Cbr%2F%3E-%20Validate%20state%22%5D%0A%20%20%20%20PA%20%26%20EA%20%26%20VA%20--%3E%20TI%5B%22Tool%20Interface%3Cbr%2F%3E(shell%2C%20files%2C%20model-agnostic)%22%5D%0A"})]),fallback:i(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<p><em>This diagram is entirely speculative and based on common multi-agent patterns combined with BIGAI&#39;s research focus.</em></p><h2 id="what-we-don-t-know" tabindex="-1">What We Don&#39;t Know <a class="header-anchor" href="#what-we-don-t-know" aria-label="Permalink to &quot;What We Don&#39;t Know&quot;">​</a></h2><ul><li>The actual number and roles of agents in the system</li><li>How agents communicate (shared memory? message passing? blackboard?)</li><li>Whether the system uses fine-tuned models or relies entirely on prompting</li><li>The specific prompt engineering techniques employed</li><li>Whether there is any training data or few-shot examples specific to terminal tasks</li><li>How the system handles the different tool-calling conventions across models</li></ul><h2 id="comparison-to-known-architectures" tabindex="-1">Comparison to Known Architectures <a class="header-anchor" href="#comparison-to-known-architectures" aria-label="Permalink to &quot;Comparison to Known Architectures&quot;">​</a></h2><p>Based on the multi-agent hypothesis, TongAgents likely shares structural similarities with:</p><ul><li><strong>CAMEL</strong> — multi-agent conversation framework (but more task-specialized)</li><li><strong>AutoGen</strong> — multi-agent orchestration (but potentially with more cognitive structure)</li><li><strong>MetaGPT</strong> — role-based multi-agent system (another Chinese AI project with similar philosophy)</li></ul><p>The key differentiator would be BIGAI&#39;s cognitive architecture influence, potentially making the agent decomposition more principled than ad-hoc role assignment.</p>',7))])}const T=r(u,[["render",d]]);export{w as __pageData,T as default};
